{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1",
  "description": "MCP policy for @metaharness/example-slack. Default-deny; read/inspect tools only. Any write to Slack requires --allow-mutations at runtime.",
  "defaultDeny": true,
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 10,
  "auditLog": true,
  "auditLogPath": ".harness/audit/mcp-calls.jsonl",
  "mutations_require_flag": "--allow-mutations",
  "grantedTools": [
    {
      "name": "slack.conversations_list",
      "description": "List channels the bot has joined (read-only). Calls GET conversations.list.",
      "safe": true,
      "needs": { "network": "slack.com", "shell": false, "fileWrite": false }
    },
    {
      "name": "slack.conversations_info",
      "description": "Fetch metadata for a single channel by ID (read-only). Calls GET conversations.info.",
      "safe": true,
      "needs": { "network": "slack.com", "shell": false, "fileWrite": false }
    },
    {
      "name": "slack.conversations_history",
      "description": "Retrieve message history from a channel (read-only). Calls GET conversations.history. Paginates via cursor.",
      "safe": true,
      "needs": { "network": "slack.com", "shell": false, "fileWrite": false }
    },
    {
      "name": "slack.conversations_replies",
      "description": "Fetch thread replies for a given ts (read-only). Calls GET conversations.replies.",
      "safe": true,
      "needs": { "network": "slack.com", "shell": false, "fileWrite": false }
    },
    {
      "name": "slack.users_info",
      "description": "Look up a Slack user by user ID (read-only). Calls GET users.info.",
      "safe": true,
      "needs": { "network": "slack.com", "shell": false, "fileWrite": false }
    },
    {
      "name": "slack.search_messages",
      "description": "Search messages visible to the bot token (read-only). Calls GET search.messages. Requires search:read scope.",
      "safe": true,
      "needs": { "network": "slack.com", "shell": false, "fileWrite": false }
    }
  ],
  "deniedTools": [
    {
      "name": "slack.chat_postMessage",
      "reason": "Write mutation. Enable with --allow-mutations."
    },
    {
      "name": "slack.chat_update",
      "reason": "Write mutation. Enable with --allow-mutations."
    },
    {
      "name": "slack.chat_delete",
      "reason": "Destructive mutation. Requires explicit user approval even with --allow-mutations."
    },
    {
      "name": "slack.reactions_add",
      "reason": "Write mutation. Enable with --allow-mutations."
    },
    {
      "name": "slack.pins_add",
      "reason": "Write mutation. Enable with --allow-mutations."
    },
    {
      "name": "slack.channels_archive",
      "reason": "Destructive mutation. Requires explicit user approval even with --allow-mutations."
    }
  ]
}
